public int active()
{
    int ret;
    FormDatasource     ProdTable_Ds;
    ProdTable        prodTable;
    boolean         orderType;

    ret =  next Active();
    ProdTable_Ds = this;
    prodTable  = ProdTable_Ds.cursor();

    ProdTable_Ds.object(fieldNum(ProdTable,BOMId)).mandatory(true);
    ProdTable_Ds.object(fieldNum(ProdTable,QtySched)).mandatory(true);
    ProdTable_Ds.object(fieldNum(ProdTable,QtySched)).visible(false);
    ProdTable_Ds.object(fieldNum(ProdTable,BOMId)).visible(false);

    //CS - Abhinav - Hide fields based on parameter - 3.02.2026 
    FormControl SubContractingGroupGroup = element.design().controlName(formControlStr(ProdTableCreate, ETGSubcontractingFields));
    SubContractingGroupGroup.visible(ETGCanadaParameters::find().EnableSubContractingPO &&  prodTable.ProdType == ProdType::Process);

    //CE

    return ret;


}

public void initValue()
{
    FormDatasource     ProdTable_Ds;
    ProdTable        prodTable;

    next initValue();

    ProdTable_Ds    = this;
    prodTable       = ProdTable_Ds.cursor();

    prodTable.DlvDate = dateNull();
    ProdTable_Ds.object(fieldNum(ProdTable,DlvDate)).mandatory(true);
    prodTable.DlvTime = timeNow();;

}

public boolean validateWrite()
{
    boolean ret;
    FormDatasource     ProdTable_Ds;
    ProdTable        prodTable;
    ProdTable_Ds    = this;
    prodTable       = ProdTable_Ds.cursor();

    prodtable.BOMId = prodtable.ETGBOMId1;

    ret =  next validatewrite();
    return  ret;
}
